mapper.select:
select

    ,

from flow_model fm
inner join `flow_category` fc on fm.category_id = fc.id
where fm.deleted = 0 and fm.status  <>  3

    and fm.status = #{ew.status}


    and fm.code = #{ew.code}


    and fm.name like concat('%', #{ew.name}, '%')


    and fc.id = #{ew.categoryId}


    and fc.code = #{ew.categoryCode}


    and fc.name like concat('%', #{ew.categoryName}, '%')

order by fm.modified_time desc

select
,
from flow_model fm left join flow_model_extend fme on fm.id = fme.model_id where fm.deleted = 0 and fm.id = #{id}
